/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `match_scoring` (
  `index` int NOT NULL AUTO_INCREMENT,
  `score_txt` float DEFAULT NULL,
  `score_img` float DEFAULT NULL,
  `final_score` float DEFAULT NULL,
  `score_type` varchar(255) DEFAULT NULL,
  `artifact_id` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`index`),
  KEY `artifact_id` (`artifact_id`),
  CONSTRAINT `match_scoring_ibfk_1` FOREIGN KEY (`artifact_id`) REFERENCES `looted_artefacts` (`artifact_id`),
  CONSTRAINT `match_scoring_ibfk_2` FOREIGN KEY (`artifact_id`) REFERENCES `looted_artefacts` (`artifact_id`)
) ENGINE=InnoDB AUTO_INCREMENT=256 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
